import logging.handlers
import os

# Define log directory and file name
LOG_DIR = '/var/log/application'
LOG_FILE_NAME = 'application.log'
LOG_PATH = os.path.join(LOG_DIR, LOG_FILE_NAME)

# Create the log directory if it doesn't exist
os.makedirs(LOG_DIR, exist_ok=True)

# Create a logger instance
logger = logging.getLogger(__name__)
logger.setLevel(logging.INFO)  # Set the minimum level for this logger

# Define a formatter for log messages
# Format: Timestamp - LoggerName - LogLevel - Message
formatter = logging.Formatter(
    '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)

# Create a rotating file handler
# This handler writes logs to a file, rotating the file after it reaches a certain size.
# It keeps a number of backup files.
# For production:
# maxBytes: Maximum size of the log file before rotation (e.g., 10 MB).
# backupCount: Number of old log files to keep (e.g., 5 files).
# This means we'll have application.log, application.log.1, application.log.2, etc.
# When application.log reaches maxBytes, it's moved to application.log.1,
# application.log.1 is moved to application.log.2, and so on. The oldest file is deleted.
rotating_file_handler = logging.handlers.RotatingFileHandler(
    LOG_PATH,
    maxBytes=10 * 1024 * 1024,  # 10 MB
    backupCount=5,
    encoding='utf-8'
)
rotating_file_handler.setLevel(logging.INFO)  # Set the minimum level for this handler
rotating_file_handler.setFormatter(formatter)
logger.addHandler(rotating_file_handler)

